import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty array for empty input");
  it.todo("should return empty array for a single live cell (underpopulation)");
  it.todo("should return empty array for two adjacent live cells (underpopulation)");
  it.todo("should keep a live cell alive when it has 2 live neighbors (survival)");
  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
  it.todo("should oscillate a vertical blinker into a horizontal blinker");
  it.todo("should keep a 2x2 block unchanged (still life)");
});
